const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

interface Step {
  op: string;
  items?: Array<{ type: string }>;
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

export function processScenario(scenario: Scenario): { results: unknown[] } {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const items = step.items ?? [];
      const basePremium = items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
      return { premium: basePremium + PROCESSING_FEE };
    }
    return {};
  });
  return { results };
}

